import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as n,e as t}from"./app-706bfe03.js";const e={},p=t(`<h1 id="html网页和结构" tabindex="-1"><a class="header-anchor" href="#html网页和结构" aria-hidden="true">#</a> HTML网页和结构</h1><h2 id="组成网页的元素" tabindex="-1"><a class="header-anchor" href="#组成网页的元素" aria-hidden="true">#</a> 组成网页的元素</h2><p>一个完整的网页组成包括HTML文本、JavaScript代码、CSS代码以及各种资源文件。</p><ul><li><p>HTML可以看成一种树状结构，网页的根节点是<code>&lt;html&gt;</code>，根下面包含<code>&lt;head&gt;</code>和<code>&lt;body&gt;</code>两个子节点</p></li><li><p>CSS是一种样式表语言，用来描述元素的显示信息。</p></li><li><p>JavaScript是一种解释型脚本语言，主要用于用户端逻辑、用户交互等，它可以修改HTML元素及其内容。</p></li></ul><p>网络上的每个资源都是由 URL (<em>Unified REsource Locator</em>)标记的，它是 URI (<em>Unified Resource Identifier</em>)的一种实现。对浏览器来说，区分两个资源是否完全相同的唯一标准就是它们的 URL 是否一致。</p><h2 id="网页结构" tabindex="-1"><a class="header-anchor" href="#网页结构" aria-hidden="true">#</a> 网页结构</h2><h3 id="框结构" tabindex="-1"><a class="header-anchor" href="#框结构" aria-hidden="true">#</a> 框结构</h3><p>框结构主要有<code>frameset</code>、<code>frame</code>、<code>iframe</code>，每个frame包含一个HTML文档，frame里的文档还可以再嵌入frame，依次类推。</p><h3 id="层次结构" tabindex="-1"><a class="header-anchor" href="#层次结构" aria-hidden="true">#</a> 层次结构</h3><p>考虑以下代码：</p><div class="language-html" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>html</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>body</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>video</span> <span class="token attr-name">src</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>xx.mp4<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token special-attr"><span class="token attr-name">style</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span><span class="token value css language-css"><span class="token property">transform</span><span class="token punctuation">:</span> <span class="token function">translateX</span><span class="token punctuation">(</span>10<span class="token punctuation">)</span></span><span class="token punctuation">&quot;</span></span></span><span class="token punctuation">&gt;</span></span>
      <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>canvas</span> <span class="token attr-name">id</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>cvs1<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>
      <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>canvas</span> <span class="token attr-name">id</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>cvs2<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>body</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>html</span><span class="token punctuation">&gt;</span></span>
</code></pre></div><p>这个网页的层次结构如下图：</p><img src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/008i3skNgy1guxcmz8j60j60bp09kq3502.jpg" style="zoom:70%;"><ul><li>当一个网页构建层次结构的时候，首先是根节点，此时自然地为它创建一个层root，它对应着整个网页文档对象</li><li>为了更有效地处理视频解码器和浏览器之间的交互和渲染问题，需要为video创建一个新的层</li><li>普通的div元素是不需要创建新层的，除非这个元素需要进行3D变换</li><li>canvas对应着HTML5标准中复杂的2D和3D绘图操作，也会创建新层</li></ul><p>总的来说，对于需要复杂变换和处理的元素，它们需要新层。</p><p>所以，webkit为它们构建新层是为了渲染引擎在处理上的方便和高效。</p><p>在构建新层的问题上，不同的渲染引擎有不同的策略。第7章会介绍webkit和chromium如何处理分层问题</p><h2 id="webkit的网页渲染过程" tabindex="-1"><a class="header-anchor" href="#webkit的网页渲染过程" aria-hidden="true">#</a> webkit的网页渲染过程</h2><h3 id="加载和渲染" tabindex="-1"><a class="header-anchor" href="#加载和渲染" aria-hidden="true">#</a> 加载和渲染</h3><p>浏览器的主要作用就是将用户输入的“URL”转变成可视化的图像。</p><p>这其中包含两个过程，其一是网页加载过程，就是从“URL”到构建DOM树；其二是网页渲染过程，从DOM树到生成可视化图像。</p><p>其实这两个过程也会交叉，很难给予明确的区分。为了简单起见，本书将这两个过程统称为网页的渲染过程。</p><h3 id="webkit的渲染过程" tabindex="-1"><a class="header-anchor" href="#webkit的渲染过程" aria-hidden="true">#</a> webkit的渲染过程</h3><p>回顾下上章介绍的<strong>网页的一般渲染过程</strong>：</p><p><img src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/008i3skNgy1guvmcd1btvj60jb06yaai02.jpg" alt=""></p><p>webkit的渲染过程当然也符合上面这个过程，下面将介绍一些细节。</p><p>根据<strong>数据的流向</strong>，将渲染过程分成三个阶段：</p><ul><li>第一阶段：从URL到构建完DOM树</li><li>第二阶段：从DOM树到构建完webkit的绘图上下文</li><li>第三阶段：从绘图上下文到生成最终的图像</li></ul><h4 id="第一阶段" tabindex="-1"><a class="header-anchor" href="#第一阶段" aria-hidden="true">#</a> 第一阶段</h4><p>下图描述的是阶段1，数字表示的是基本顺序，当然也不是严格一致，因为过程可能重复或交叉。</p><p><img src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/008i3skNgy1guxmvo4i5pj60d506pglu02.jpg" alt=""></p><p>具体过成如下：</p><ol><li><p>输入URL时，webkit调用资源加载起加载URL对应的网页</p></li><li><p>加载器依赖网络模块建立连接，发送请求并接受答复</p></li><li><p>webkit接收到各种资源数据，某些资源可能是同步或异步获取的</p></li><li><p>网页被交给HTML解释器转换成一系列的token</p></li><li><p>解释器根据token构建节点(Node)，形成DOM树</p></li><li><p>如果Node是JS代码，调用JS引擎解释并执行</p></li><li><p>JS代码可能修改DOM树</p></li><li><p>如果Node依赖其他资源，调用资源加载器来加载它们。</p><p>如果是图片、css、视频等资源，它们会被异步加载，不会阻碍当前DOM树的继续构建；</p><p>如果是JavaScript资源（没有标记异步方式），则需要停止当前DOM树的构建，直到JS被加载且执行完毕（因为JS能修改DOM）。</p></li></ol><p>上述过程中，网页在加载和渲染过程中会发出 <code>DOMContent</code> 事件和DOM的 <code>onload</code> 事件，分别在DOM树构建完成之后，以及DOM构建完且网页依赖的资源都加载完之后发生。由于某些资源的加载不会阻碍DOM树的构建，所以这两个事件多数时候不是同时发生的。</p><h4 id="第二阶段" tabindex="-1"><a class="header-anchor" href="#第二阶段" aria-hidden="true">#</a> 第二阶段</h4><p>第二阶段就是webkit利用css和DOM构建 RenderObject树直到绘图上下文。过程如下：</p><p><img src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/008i3skNgy1guxmvmc4a6j608g079dfx02.jpg" alt=""></p><ol><li>css文件被css解释器转化成内部表示结构</li><li>css解释器工作完成后，在DOM树上附加解释后的样式信息，就是 RenderObject 树</li><li>RenderObject 节点在创建的同时，webkit会根据网页的层次结构创建 RenderLayer 树，同时构建一个虚拟的绘图上下文。（其实这中间还有复杂的内部过程，具体在后面的章节做详细介绍）</li></ol><h4 id="第三阶段" tabindex="-1"><a class="header-anchor" href="#第三阶段" aria-hidden="true">#</a> 第三阶段</h4><p>第三阶段就是根据绘图上下文来生成最终的图像，这一过程主要依赖2D和3D图形库。</p><p><img src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/008i3skNgy1guxmvkxigzj60bd04aaa202.jpg" alt=""></p><ol><li><p>绘图上下文是一个与平台无关的抽象类，它将每个绘图操作桥接到不同的具体实现类。</p></li><li><p>绘图实现类可能简单也可能复杂。</p><p>比如在 Chromium 中，需要 Chromium 的合成器来完成复杂的多进程和 GPU 加速机制，这在后面会介绍。</p></li><li><p>绘图实现类将2D、3D图形库绘制的结果保存下来，交给浏览器来显示。</p></li></ol><p>现代浏览器为了绘图上的高效性和安全性，可能会在绘制过程中引入复杂的机制。而且，绘图也从之前单纯的软件渲染，到现在的GPU硬件渲染、混合渲染模型等方式，这些同样会以单独的章节加以剖析。</p><p>上面介绍的是一个完整的渲染过程。事实上，在一次渲染完成后，由于网页的动画或者用户的交互，浏览器其实一直在不停地重复执行渲染过程。</p>`,44),c=[p];function o(i,l){return s(),n("div",null,c)}const d=a(e,[["render",o],["__file","2. HTML网页和结构.html.vue"]]);export{d as default};
